231→// ---------------------------------------------------------------------------
232→// HeaderOpenButton — split button: quick open (last-used) + dropdown
233→// ---------------------------------------------------------------------------
234→
235→function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
236→  const [apps, setApps] = useState<InstalledApp[]>([]);
237→  const [loading, setLoading] = useState(true);
238→  const [open, setOpen] = useState(false);
239→  const [copied, setCopied] = useState(false);
240→  const [lastAppId, setLastAppId] = useLastOpenInApp();
241→  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
242→  const isHoveringRef = useRef(false);
243→
244→  useEffect(() => {
245→    native.apps
246→      .getInstalled()
247→      .then(setApps)
248→      .catch(() => {})
249→      .finally(() => setLoading(false));
250→  }, []);
251→
252→  // Default app: last-used, or first editor in the list
253→  const lastApp = lastAppId ? (apps.find((a) => a.id === lastAppId) ?? null) : null;
254→  const defaultApp = lastApp ?? apps[0] ?? null;
255→
256→  function handleOpenInApp(appId: string) {
257→    setOpen(false);
258→    setLastAppId(appId);
259→    track("open_in_app", { app_id: appId });
260→    native.apps.openIn(appId, workspacePath).catch(() => {});
261→  }
262→
263→  function handleQuickOpen() {
264→    if (loading) return;
265→    if (defaultApp) {
266→      handleOpenInApp(defaultApp.id);
267→    } else {
268→      setOpen(true);
269→    }
270→  }
271→
272→  function handleCopyPath() {
273→    navigator.clipboard
274→      .writeText(workspacePath)
275→      .then(() => {
276→        setCopied(true);
277→        setTimeout(() => setCopied(false), 2000);
278→      })
279→      .catch(() => {});
280→    setOpen(false);
281→  }
282→
283→  function handleOpen() {
284→    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
285→    isHoveringRef.current = true;
286→    setOpen(true);
287→  }
288→
289→  function handleClose() {
290→    isHoveringRef.current = false;
291→    closeTimeoutRef.current = setTimeout(() => {
292→      if (!isHoveringRef.current) setOpen(false);
293→    }, 50);
294→  }
295→
296→  useEffect(() => {
297→    return () => {
298→      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
299→    };
300→  }, []);
301→
302→  // Hide only after loading confirms no apps installed (web mode)
303→  if (!loading && apps.length === 0) {
304→    return null;
305→  }
306→
307→  const groups = groupAppsByCategory(apps);
308→
309→  return (
310→    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
311→      <div className="border-border-strong flex h-7 shrink-0 items-center rounded-lg border">
312→        {/* Left: quick-open action */}
313→        <Tooltip delayDuration={200}>
314→          <TooltipTrigger asChild>
315→            <button
316→              type="button"
317→              onClick={handleQuickOpen}
318→              className="text-text-subtle hover:bg-bg-muted flex h-full shrink-0 items-center gap-1.5 rounded-l-lg px-2 transition-colors duration-200"
319→            >
320→              {defaultApp?.icon ? (
321→                <img
322→                  src={defaultApp.icon}
323→                  alt=""
324→                  className="h-4 w-4 shrink-0 rounded-xs"
325→                  draggable={false}
326→                />
327→              ) : (
328→                <ArrowUpRight className="h-[11px] w-[11px] shrink-0" />
329→              )}
330→              <span className="shrink-0 text-sm font-medium">Open</span>
331→            </button>
332→          </TooltipTrigger>
333→          <TooltipContent side="bottom">
334→            <p className="text-xs">
335→              {defaultApp ? `Open in ${defaultApp.name}` : "Open in\u2026"}
336→              <span className="text-text-muted ml-2">⌘O</span>
337→            </p>
338→          </TooltipContent>
339→        </Tooltip>
340→
341→        {/* Divider */}
342→        <div className="bg-border-strong h-4 w-px shrink-0" />
343→
344→        {/* Right: dropdown chevron */}
345→        <DropdownMenuTrigger asChild>
346→          <button
347→            type="button"
348→            aria-label="Choose app to open in"
349→            className="text-text-muted hover:bg-bg-muted hover:text-text-subtle flex h-full shrink-0 items-center rounded-r-lg px-1.5 transition-colors duration-200"
350→            onPointerEnter={handleOpen}
351→            onPointerLeave={handleClose}
352→          >
353→            <ChevronDown className="h-2.5 w-2.5" />
354→          </button>
355→        </DropdownMenuTrigger>
356→      </div>
357→
358→      <DropdownMenuContent
359→        align="end"
360→        sideOffset={4}
361→        className="min-w-[140px] shadow-sm"
362→        onPointerEnter={handleOpen}
363→        onPointerLeave={handleClose}
364→      >
365→        {groups.map((group, groupIdx) => (
366→          <div key={group.category}>
367→            {groupIdx > 0 && <DropdownMenuSeparator />}
368→            {group.apps.map((app) => (
369→              <DropdownMenuItem
370→                key={app.id}
371→                onClick={() => handleOpenInApp(app.id)}
372→                className="cursor-pointer gap-2 py-1 text-xs"
373→              >
374→                {app.icon ? (
375→                  <img
376→                    src={app.icon}
377→                    alt=""
378→                    className="h-5 w-5 flex-shrink-0 rounded-xs"
379→                    draggable={false}
380→                  />
381→                ) : (
382→                  <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
383→                )}
384→                <span className={lastApp?.id === app.id ? "font-medium" : ""}>{app.name}</span>
385→                {lastApp?.id === app.id && <Check className="text-text-muted ml-auto h-3 w-3" />}
386→              </DropdownMenuItem>
387→            ))}
388→          </div>
389→        ))}
390→        <DropdownMenuSeparator />
391→        <DropdownMenuItem
392→          onClick={handleCopyPath}
393→          className="text-text-muted cursor-pointer gap-2 py-1 text-xs"
394→        >
395→          {copied ? (
396→            <Check className="h-3.5 w-3.5 flex-shrink-0" />
397→          ) : (
398→            <Copy className="h-3.5 w-3.5 flex-shrink-0" />
399→          )}
400→          {copied ? "Copied!" : "Copy path"}
401→        </DropdownMenuItem>
402→      </DropdownMenuContent>
403→    </DropdownMenu>
404→  );
405→}
