import { useState, useEffect, useRef } from "react";
import {
  ArrowUpRight,
  ChevronDown,
  PanelLeft,
  AlertTriangle,
  Loader2,
  RotateCw,
  ScrollText,
  Sparkles,
  Copy,
  Check,
} from "lucide-react";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { useSidebar } from "@/components/ui/sidebar";
import { cn } from "@/shared/lib/utils";
import { native } from "@/platform";
import type { InstalledApp } from "@/platform";
import { track } from "@/platform/analytics";
import type { SetupStatus } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import type { NormalizedTask } from "../api/workspace.service";
import { HeaderRunButton } from "./HeaderRunButton";
import { WorkflowStatusIcon } from "@/features/sidebar/ui/WorkflowStatusIcon";
import { WorkspaceStatusMenu } from "@/features/sidebar/ui/WorkspaceStatusMenu";
import { WORKFLOW_STATUS_CONFIG } from "@/features/sidebar/lib/status";
import { AppIcon, groupAppsByCategory } from "@/shared/lib/appIcons";
import { useLastOpenInApp } from "@/shared/hooks/useLastOpenInApp";
import { fixSetupErrorPrompt, GENERATE_HIVE_JSON } from "@/features/session/lib/sessionPrompts";

interface WorkspaceHeaderProps {
  title?: string;
  repositoryName?: string;
  branch?: string;
  workspacePath?: string;
  setupStatus?: SetupStatus;
  setupError?: string | null;
  onSendAgentMessage?: (text: string) => void;
  onRetrySetup?: () => void;
  onViewSetupLogs?: () => void;
  workspaceStatus?: WorkspaceStatus;
  onStatusChange?: (status: WorkspaceStatus) => void;
  tasks?: NormalizedTask[];
  hasManifest?: boolean;
  onRunTask?: (taskName: string) => void;
  /** Compact mode for mobile -- always show hamburger, hide Open button, tighter truncation */
  mobile?: boolean;
}

/**
 * Workspace title header — sits at the top of the LEFT (chat) panel.
 *
 * Simple 36px bar: title + repo/branch on left, Open button on right.
 * PR actions have moved to the right panel's ContentPanelHeader.
 */
export function WorkspaceHeader({
  title,
  repositoryName,
  branch,
  workspacePath,
  setupStatus,
  setupError,
  onSendAgentMessage,
  onRetrySetup,
  onViewSetupLogs,
  workspaceStatus,
  onStatusChange,
  tasks,
  hasManifest,
  onRunTask,
  mobile,
}: WorkspaceHeaderProps) {
  const { state: sidebarState, toggleSidebar } = useSidebar();
  const sidebarCollapsed = sidebarState === "collapsed";
  const showSidebarToggle = sidebarCollapsed || mobile;

  const subtitle = [repositoryName, branch].filter(Boolean).join(" / ");

  return (
    <div
      data-slot="workspace-header"
      className="drag-region flex h-11 flex-shrink-0 items-center justify-between gap-4 px-4"
    >
      {/* Left: sidebar toggle + title + repo/branch */}
      <div className="flex min-w-0 items-center gap-[5px] overflow-hidden">
        {showSidebarToggle && (
          <Tooltip delayDuration={200}>
            <TooltipTrigger asChild>
              <button
                type="button"
                aria-label="Expand sidebar"
                onClick={toggleSidebar}
                className="text-text-muted hover:text-text-secondary hover:bg-bg-muted mr-1 -ml-1 flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-lg transition-colors duration-200"
              >
                <PanelLeft className="h-3.5 w-3.5" />
              </button>
            </TooltipTrigger>
            <TooltipContent side="bottom">
              <p className="text-xs">Open sidebar</p>
            </TooltipContent>
          </Tooltip>
        )}

        {workspaceStatus && onStatusChange && (
          <WorkspaceStatusMenu currentStatus={workspaceStatus} onStatusChange={onStatusChange}>
            <button
              type="button"
              className="text-text-muted hover:text-text-secondary mr-1 flex items-center gap-1 rounded-lg px-1 py-0.5 transition-colors duration-200"
            >
              <WorkflowStatusIcon status={workspaceStatus} size={14} />
            </button>
          </WorkspaceStatusMenu>
        )}

        {title && (
          <span
            className={cn(
              "text-foreground mr-0.5 truncate text-sm font-medium",
              mobile ? "max-w-[120px]" : "max-w-[200px]"
            )}
          >
            {title}
          </span>
        )}

        {subtitle && (
          <span
            className={cn(
              "truncate text-sm font-medium",
              mobile ? "max-w-[140px]" : "max-w-[200px]",
              title ? "text-text-subtle" : "text-foreground"
            )}
            title={subtitle}
          >
            {subtitle}
          </span>
        )}

        {setupStatus === "running" && (
          <span className="text-text-muted flex items-center gap-1 text-sm">
            <Loader2 className="h-3 w-3 animate-spin" />
            <span>Installing...</span>
          </span>
        )}
        {setupStatus === "failed" && (
          <div className="flex items-center gap-1">
            <span className="text-accent-red-muted flex items-center gap-1 text-sm font-medium">
              <AlertTriangle className="h-3 w-3" />
              <span>Setup failed</span>
            </span>
            {onViewSetupLogs && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={onViewSetupLogs}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <ScrollText className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">View setup logs</p>
                </TooltipContent>
              </Tooltip>
            )}
            {onSendAgentMessage && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={() => onSendAgentMessage(fixSetupErrorPrompt(setupError ?? null))}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <Sparkles className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">Ask AI to fix</p>
                </TooltipContent>
              </Tooltip>
            )}
            {onRetrySetup && (
              <Tooltip delayDuration={200}>
                <TooltipTrigger asChild>
                  <button
                    type="button"
                    onClick={onRetrySetup}
                    className="text-text-muted hover:text-text-secondary rounded-lg px-1.5 py-0.5 text-xs transition-colors duration-200"
                  >
                    <RotateCw className="h-3 w-3" />
                  </button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  <p className="text-xs">Retry setup</p>
                </TooltipContent>
              </Tooltip>
            )}
          </div>
        )}
      </div>

      {/* Right: Run + Open buttons (desktop only) */}
      {!mobile && (
        <div className="flex items-center gap-2">
          {onRunTask && (
            <HeaderRunButton
              tasks={tasks ?? []}
              hasManifest={hasManifest ?? false}
              disabled={setupStatus === "running"}
              onRunTask={onRunTask}
              onSetupEnvironment={
                onSendAgentMessage ? () => onSendAgentMessage(GENERATE_HIVE_JSON) : undefined
              }
            />
          )}
          {workspacePath && <HeaderOpenButton workspacePath={workspacePath} />}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// HeaderOpenButton — split button: quick open (last-used) + dropdown
// ---------------------------------------------------------------------------

function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
  const [apps, setApps] = useState<InstalledApp[]>([]);
  const [loading, setLoading] = useState(true);
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const [lastAppId, setLastAppId] = useLastOpenInApp();
  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const isHoveringRef = useRef(false);

  useEffect(() => {
    native.apps
      .getInstalled()
      .then(setApps)
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  // Default app: last-used, or first editor in the list
  const lastApp = lastAppId ? (apps.find((a) => a.id === lastAppId) ?? null) : null;
  const defaultApp = lastApp ?? apps[0] ?? null;

  function handleOpenInApp(appId: string) {
    setOpen(false);
    setLastAppId(appId);
    track("open_in_app", { app_id: appId });
    native.apps.openIn(appId, workspacePath).catch(() => {});
  }

  function handleQuickOpen() {
    if (loading) return;
    if (defaultApp) {
      handleOpenInApp(defaultApp.id);
    } else {
      setOpen(true);
    }
  }

  function handleCopyPath() {
    navigator.clipboard
      .writeText(workspacePath)
      .then(() => {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      })
      .catch(() => {});
    setOpen(false);
  }

  function handleOpen() {
    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    isHoveringRef.current = true;
    setOpen(true);
  }

  function handleClose() {
    isHoveringRef.current = false;
    closeTimeoutRef.current = setTimeout(() => {
      if (!isHoveringRef.current) setOpen(false);
    }, 50);
  }

  useEffect(() => {
    return () => {
      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
    };
  }, []);

  // Hide only after loading confirms no apps installed (web mode)
  if (!loading && apps.length === 0) {
    return null;
  }

  const groups = groupAppsByCategory(apps);

  return (
    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
      <div className="border-border-strong flex h-7 shrink-0 items-center rounded-lg border">
        {/* Left: quick-open action */}
        <Tooltip delayDuration={200}>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={handleQuickOpen}
              className="text-text-subtle hover:bg-bg-muted flex h-full shrink-0 items-center gap-1.5 rounded-l-lg px-2 transition-colors duration-200"
            >
              {defaultApp?.icon ? (
                <img
                  src={defaultApp.icon}
                  alt=""
                  className="h-4 w-4 shrink-0 rounded-xs"
                  draggable={false}
                />
              ) : (
                <ArrowUpRight className="h-[11px] w-[11px] shrink-0" />
              )}
              <span className="shrink-0 text-sm font-medium">Open</span>
            </button>
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p className="text-xs">
              {defaultApp ? `Open in ${defaultApp.name}` : "Open in\u2026"}
              <span className="text-text-muted ml-2">⌘O</span>
            </p>
          </TooltipContent>
        </Tooltip>

        {/* Divider */}
        <div className="bg-border-strong h-4 w-px shrink-0" />

        {/* Right: dropdown chevron */}
        <DropdownMenuTrigger asChild>
          <button
            type="button"
            aria-label="Choose app to open in"
            className="text-text-muted hover:bg-bg-muted hover:text-text-subtle flex h-full shrink-0 items-center rounded-r-lg px-1.5 transition-colors duration-200"
            onPointerEnter={handleOpen}
            onPointerLeave={handleClose}
          >
            <ChevronDown className="h-2.5 w-2.5" />
          </button>
        </DropdownMenuTrigger>
      </div>

      <DropdownMenuContent
        align="end"
        sideOffset={4}
        className="min-w-[140px] shadow-sm"
        onPointerEnter={handleOpen}
        onPointerLeave={handleClose}
      >
        {groups.map((group, groupIdx) => (
          <div key={group.category}>
            {groupIdx > 0 && <DropdownMenuSeparator />}
            {group.apps.map((app) => (
              <DropdownMenuItem
                key={app.id}
                onClick={() => handleOpenInApp(app.id)}
                className="cursor-pointer gap-2 py-1 text-xs"
              >
                {app.icon ? (
                  <img
                    src={app.icon}
                    alt=""
                    className="h-5 w-5 flex-shrink-0 rounded-xs"
                    draggable={false}
                  />
                ) : (
                  <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
                )}
                <span className={lastApp?.id === app.id ? "font-medium" : ""}>{app.name}</span>
                {lastApp?.id === app.id && <Check className="text-text-muted ml-auto h-3 w-3" />}
              </DropdownMenuItem>
            ))}
          </div>
        ))}
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={handleCopyPath}
          className="text-text-muted cursor-pointer gap-2 py-1 text-xs"
        >
          {copied ? (
            <Check className="h-3.5 w-3.5 flex-shrink-0" />
          ) : (
            <Copy className="h-3.5 w-3.5 flex-shrink-0" />
          )}
          {copied ? "Copied!" : "Copy path"}
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

/**
 * MobilePRBar -- compact PR status UI for mobile web layout.
 *
 * Two exports:
 *   MobilePRHeaderAction  -- "Create PR" pill for the header row (no-PR state only)
 *   MobilePRStatusBar     -- 32px bar below header (all states with an existing PR)
 *
 * Uses the same derivePRActionState function as the desktop PRActions component
 * to keep state logic unified. Only the presentation differs.
 */

import { useState } from "react";
import {
  GitPullRequestCreate,
  GitPullRequestClosed,
  GitMerge,
  CircleX,
  FileWarning,
  MessageSquareWarning,
  Archive,
  Loader2,
  ChevronDown,
  ExternalLink,
} from "lucide-react";
import { match } from "ts-pattern";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/shared/lib/utils";
import { BranchSelector } from "@/features/workspace/ui/BranchSelector";
import { derivePRActionState } from "@/features/workspace/lib/prState";
import {
  RESOLVE_CONFLICTS,
  fixCIPrompt,
  ADDRESS_REVIEW,
  MERGE_PR,
} from "@/features/session/lib/sessionPrompts";
import { track } from "@/platform/analytics";
import type { PRStatus, GhCliStatus } from "@/shared/types";

// ---------------------------------------------------------------------------
// Shared props
// ---------------------------------------------------------------------------

interface MobilePRBarProps {
  prStatus: PRStatus | null;
  ghStatus?: GhCliStatus | null;
  onCreatePR?: () => void;
  onSendAgentMessage?: (text: string) => void;
  onArchive?: () => void;
  targetBranch: string;
  onTargetBranchChange: (branch: string) => void;
  workspaceId?: string;
  repoId?: string;
}

// ---------------------------------------------------------------------------
// MobilePRHeaderAction -- compact "Create PR" pill for the header row
// ---------------------------------------------------------------------------

/**
 * Renders a small "Create PR" pill in the mobile header.
 * Only visible when no PR exists yet. Returns null otherwise.
 */
export function MobilePRHeaderAction({
  prStatus,
  ghStatus,
  onCreatePR,
  onArchive,
  targetBranch,
  onTargetBranchChange,
  repoId,
}: MobilePRBarProps) {
  const [sheetOpen, setSheetOpen] = useState(false);
  const state = derivePRActionState(prStatus, ghStatus, targetBranch);

  if (state.type !== "no_pr") return null;

  return (
    <>
      <button
        type="button"
        onClick={() => setSheetOpen(true)}
        disabled={!onCreatePR}
        className={cn(
          "bg-primary text-primary-foreground flex h-7 flex-shrink-0 items-center gap-1.5 rounded-full px-3 text-xs font-semibold transition-opacity duration-200",
          !onCreatePR ? "cursor-not-allowed opacity-50" : "hover:opacity-90"
        )}
      >
        <GitPullRequestCreate className="h-3 w-3" />
        <span>Create PR</span>
      </button>

      <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
        <SheetContent side="bottom" className="rounded-t-xl">
          <SheetHeader>
            <SheetTitle>Create Pull Request</SheetTitle>
            <SheetDescription>Select target branch and create a PR.</SheetDescription>
          </SheetHeader>

          <div className="flex flex-col gap-4 px-4 pb-4">
            {/* Target branch selector */}
            <div className="flex flex-col gap-2">
              <span className="text-text-muted text-xs font-medium">Target branch</span>
              <BranchSelector
                repoId={repoId ?? null}
                currentBranch={targetBranch}
                onBranchSelect={onTargetBranchChange}
              >
                <button
                  type="button"
                  className="border-border-subtle bg-bg-elevated flex h-10 w-full items-center justify-between rounded-lg border px-3 text-sm"
                >
                  <span className="text-foreground font-medium">{targetBranch}</span>
                  <ChevronDown className="text-text-muted h-3.5 w-3.5" />
                </button>
              </BranchSelector>
            </div>

            {/* Create PR action */}
            <button
              type="button"
              onClick={() => {
                onCreatePR?.();
                setSheetOpen(false);
              }}
              disabled={!onCreatePR}
              className={cn(
                "bg-primary text-primary-foreground flex h-10 w-full items-center justify-center gap-2 rounded-lg text-sm font-semibold transition-opacity duration-200",
                !onCreatePR ? "cursor-not-allowed opacity-50" : "hover:opacity-90"
              )}
            >
              <GitPullRequestCreate className="h-4 w-4" />
              Create PR
            </button>

            {/* Archive secondary action */}
            {onArchive && (
              <>
                <Separator />
                <button
                  type="button"
                  onClick={() => {
                    onArchive();
                    setSheetOpen(false);
                  }}
                  className="text-text-muted hover:text-text-secondary flex h-9 w-full items-center justify-center gap-2 text-sm transition-colors duration-200"
                >
                  <Archive className="h-3.5 w-3.5" />
                  Archive workspace
                </button>
              </>
            )}
          </div>
        </SheetContent>
      </Sheet>
    </>
  );
}

// ---------------------------------------------------------------------------
// MobilePRStatusBar -- 32px bar for states with an existing PR
// ---------------------------------------------------------------------------

/**
 * Renders a compact status bar below the mobile header showing PR status.
 * Only visible when a PR exists. Returns null for no_pr, gh_unavailable, and error.
 */
export function MobilePRStatusBar({
  prStatus,
  ghStatus,
  onSendAgentMessage,
  onArchive,
  targetBranch,
  workspaceId,
}: MobilePRBarProps) {
  const state = derivePRActionState(prStatus, ghStatus, targetBranch);

  return match(state)
    .with({ type: "gh_unavailable" }, () => null)
    .with({ type: "error" }, () => null)
    .with({ type: "no_pr" }, () => null)
    .with({ type: "ci_pending" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-warning flex items-center gap-1 text-xs">
          <Loader2 className="h-3 w-3 animate-spin" strokeWidth={1.5} />
          {s.checksTotal > 0 ? `${s.checksDone}/${s.checksTotal} checks` : "Checks running"}
        </span>
      </StatusBar>
    ))
    .with({ type: "ci_failing" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-destructive flex items-center gap-1 text-xs">
          <CircleX className="h-3 w-3" />
          CI failing
        </span>
        <BarAction
          label="Fix CI"
          variant="destructive"
          onClick={() => onSendAgentMessage?.(fixCIPrompt(s.failingChecks))}
          disabled={!onSendAgentMessage}
        />
      </StatusBar>
    ))
    .with({ type: "conflicts" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-destructive flex items-center gap-1 text-xs">
          <FileWarning className="h-3 w-3" />
          Conflicts
        </span>
        <BarAction
          label="Resolve"
          variant="destructive"
          onClick={() => onSendAgentMessage?.(RESOLVE_CONFLICTS)}
          disabled={!onSendAgentMessage}
        />
      </StatusBar>
    ))
    .with({ type: "changes_requested" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-warning flex items-center gap-1 text-xs">
          <MessageSquareWarning className="h-3 w-3" />
          Changes requested
        </span>
        <BarAction
          label="Address"
          variant="warning"
          onClick={() => onSendAgentMessage?.(ADDRESS_REVIEW)}
          disabled={!onSendAgentMessage}
        />
      </StatusBar>
    ))
    .with({ type: "ready_to_merge" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-success flex items-center gap-1 text-xs">
          <GitMerge className="h-3 w-3" />
          Ready
        </span>
        <BarAction
          label="Merge"
          variant="success"
          onClick={() => {
            if (workspaceId) {
              track("pr_merged", { workspace_id: workspaceId, pr_number: s.prNumber });
            }
            onSendAgentMessage?.(MERGE_PR);
          }}
          disabled={!onSendAgentMessage}
        />
      </StatusBar>
    ))
    .with({ type: "awaiting_review" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-text-muted text-xs">Awaiting review</span>
      </StatusBar>
    ))
    .with({ type: "merged" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-text-muted flex items-center gap-1 text-xs">
          <GitMerge className="h-3 w-3" />
          Merged
        </span>
        {onArchive && <BarAction label="Archive" variant="primary" onClick={onArchive} />}
      </StatusBar>
    ))
    .with({ type: "closed" }, (s) => (
      <StatusBar prNumber={s.prNumber} prUrl={s.prUrl}>
        <span className="text-text-muted flex items-center gap-1 text-xs">
          <GitPullRequestClosed className="h-3 w-3" />
          Closed
        </span>
      </StatusBar>
    ))
    .exhaustive();
}

// ---------------------------------------------------------------------------
// StatusBar -- shared layout wrapper for the 32px bar
// ---------------------------------------------------------------------------

function StatusBar({
  prNumber,
  prUrl,
  children,
}: {
  prNumber: number;
  prUrl: string;
  children: React.ReactNode;
}) {
  return (
    <div
      data-slot="mobile-pr-bar"
      className="border-border-subtle flex h-8 flex-shrink-0 items-center gap-2 border-b px-4"
    >
      {/* PR link */}
      <a
        href={prUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="text-text-muted hover:text-text-secondary flex flex-shrink-0 items-center gap-1 text-xs font-semibold transition-colors duration-200"
      >
        <GitPullRequestCreate className="h-3 w-3" />#{prNumber}
        <ExternalLink className="h-2.5 w-2.5" />
      </a>

      {/* Separator dot */}
      <span className="bg-border-subtle h-0.5 w-0.5 flex-shrink-0 rounded-full" />

      {/* Status + optional action -- pushed apart */}
      <div className="flex min-w-0 flex-1 items-center justify-between gap-2">{children}</div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// BarAction -- compact action button for the status bar
// ---------------------------------------------------------------------------

const BAR_VARIANT_CLASSES = {
  primary: "bg-primary text-primary-foreground",
  destructive: "bg-destructive text-destructive-foreground",
  warning: "bg-warning text-warning-foreground",
  success: "bg-success text-success-foreground",
} as const;

function BarAction({
  label,
  variant,
  onClick,
  disabled,
}: {
  label: string;
  variant: keyof typeof BAR_VARIANT_CLASSES;
  onClick: () => void;
  disabled?: boolean;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={cn(
        "flex h-5.5 flex-shrink-0 items-center rounded-md px-2 text-xs font-semibold transition-opacity duration-200",
        BAR_VARIANT_CLASSES[variant],
        disabled ? "cursor-not-allowed opacity-50" : "hover:opacity-90"
      )}
    >
      {label}
    </button>
  );
}

