/**
 * MobileLayout -- single-panel mobile layout with bottom tab bar.
 *
 * Replaces the desktop ResizablePanelGroup on screens < 768px.
 * Two views: Chat (full-width ChatArea) and Code (full-width AllFilesDiffViewer).
 * Chat is the default -- "AI chat as a first-class citizen".
 */

import { useState, useMemo } from "react";
import type { Dispatch, SetStateAction } from "react";
import type { SessionPanelRef } from "@/features/session";
import { useFileChanges } from "@/features/workspace";
import { AllFilesDiffViewer } from "@/features/workspace/ui/AllFilesDiffViewer";
import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import type { NormalizedTask } from "@/features/workspace/api/workspace.service";
import { cn } from "@/shared/lib/utils";
import { ChatArea } from "./ChatArea";
import { MobileTabBar } from "./MobileTabBar";
import type { MobileTab } from "./MobileTabBar";
import { MobilePRHeaderAction, MobilePRStatusBar } from "./MobilePRBar";

interface MobileLayoutProps {
  workspace: Workspace;
  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
  sendAgentMessageHandler: ((text: string) => Promise<void>) | null;
  handleSendAgentMessage: (text: string) => void;
  /** Pre-gated by caller: only passed when setup_status === "failed" */
  onRetrySetup?: () => void;
  /** Pre-gated by caller: only passed when setup_status === "failed" */
  onViewSetupLogs?: () => void;
  setCreatePRHandler: (handler: (() => void) | null) => void;
  setSendAgentMessageHandler: Dispatch<SetStateAction<((text: string) => Promise<void>) | null>>;
  isWatched: boolean;
  manifestTasks?: NormalizedTask[];
  hasManifest?: boolean;
  onRunTask?: (taskName: string) => void;
  onStatusChange?: (status: WorkspaceStatus) => void;
  // PR actions
  prStatus: PRStatus | null;
  ghStatus?: GhCliStatus | null;
  onCreatePR?: () => void;
  onArchive?: () => void;
  targetBranch: string;
  onTargetBranchChange: (branch: string) => void;
}

export function MobileLayout({
  workspace,
  workspaceChatPanelRef,
  sendAgentMessageHandler,
  handleSendAgentMessage,
  onRetrySetup,
  onViewSetupLogs,
  setCreatePRHandler,
  setSendAgentMessageHandler,
  isWatched,
  manifestTasks,
  hasManifest,
  onRunTask,
  onStatusChange,
  prStatus,
  ghStatus,
  onCreatePR,
  onArchive,
  targetBranch,
  onTargetBranchChange,
}: MobileLayoutProps) {
  const [activeTab, setActiveTab] = useState<MobileTab>("chat");

  // File changes -- always queried for the badge count on the code tab,
  // and used by AllFilesDiffViewer when the code tab is active.
  const isReady = workspace.state === "ready";
  const { data: fileChangesData } = useFileChanges(
    isReady ? workspace.id : null,
    workspace.session_status,
    isWatched,
    workspace.state
  );
  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);

  // Shared PR bar props -- avoids repeating the same prop bag twice.
  const prBarProps = {
    prStatus,
    ghStatus,
    onCreatePR,
    onSendAgentMessage: sendAgentMessageHandler ? handleSendAgentMessage : undefined,
    onArchive,
    targetBranch,
    onTargetBranchChange,
    workspaceId: workspace.id,
    repoId: workspace.repository_id,
  };

  return (
    <div className="flex h-dvh min-w-0 flex-col overflow-hidden">
      {/* Header row -- workspace title on left, compact Create PR pill on right */}
      <div className="flex flex-shrink-0 items-center justify-between pr-2">
        <WorkspaceHeader
          title={workspace.title ?? undefined}
          repositoryName={workspace.repo_name}
          branch={workspace.git_branch ?? undefined}
          workspacePath={workspace.workspace_path}
          setupStatus={workspace.setup_status}
          setupError={workspace.error_message}
          onSendAgentMessage={sendAgentMessageHandler ? handleSendAgentMessage : undefined}
          onRetrySetup={onRetrySetup}
          onViewSetupLogs={onViewSetupLogs}
          workspaceStatus={workspace.status}
          onStatusChange={onStatusChange}
          tasks={manifestTasks}
          hasManifest={hasManifest}
          onRunTask={onRunTask}
          mobile
        />
        <MobilePRHeaderAction {...prBarProps} />
      </div>

      {/* PR status bar -- only shown when a PR exists, 32px */}
      <MobilePRStatusBar {...prBarProps} />

      {/* Content area -- both views always mounted, inactive hidden via display:none */}
      <div
        className={cn(
          "flex min-h-0 flex-1 flex-col overflow-hidden",
          activeTab !== "chat" && "hidden"
        )}
        id="mobile-panel-chat"
        role="tabpanel"
        aria-labelledby="mobile-tab-chat"
      >
        <ChatArea
          key={workspace.id}
          workspace={workspace}
          workspaceChatPanelRef={workspaceChatPanelRef}
          onCreatePRHandlerChange={setCreatePRHandler}
          onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
        />
      </div>

      {/* Code panel -- absolute positioning gives AllFilesDiffViewer's h-full a proper
          height context (h-full doesn't resolve inside flex-grown parents). */}
      <div
        className={cn("relative min-h-0 flex-1", activeTab !== "code" && "hidden")}
        id="mobile-panel-code"
        role="tabpanel"
        aria-labelledby="mobile-tab-code"
      >
        {fileChanges.length === 0 ? (
          <div className="flex h-full items-center justify-center">
            <p className="text-text-muted text-sm">No file changes yet</p>
          </div>
        ) : (
          <div className="absolute inset-0 overflow-y-auto px-2 pt-2">
            <AllFilesDiffViewer workspaceId={workspace.id} fileChanges={fileChanges} hideHeader />
          </div>
        )}
      </div>

      {/* Bottom tab bar */}
      <MobileTabBar
        activeTab={activeTab}
        onTabChange={setActiveTab}
        fileChangesCount={fileChanges.length}
      />
    </div>
  );
}

/**
 * AllFilesDiffViewer — Scrollable container for all changed files' diffs.
 *
 * Renders each changed file as an AllDiffFileSection with lazy loading.
 * Exposes `scrollToFile(path)` via ref for bidirectional sync with the file tree.
 * Tracks which file is currently visible and reports it via `onActiveFileChange`.
 *
 * Scroll-spy: uses a scroll event listener on the container to find the topmost
 * visible section. This is simpler and more reliable than distributed
 * IntersectionObservers across memoized children (which suffer stale closure
 * and content-visibility timing issues).
 *
 * Performance: CSS containment per section, IntersectionObserver lazy loading,
 * React.memo per section, rAF-throttled scroll spy.
 */

import { forwardRef, useImperativeHandle, useRef, useCallback, useState, useEffect } from "react";
import { ChevronsUpDown } from "lucide-react";
import { AllDiffFileSection } from "./AllDiffFileSection";
import { workspaceLayoutActions } from "../store";
import type { FileChange } from "@/shared/types";

export interface AllFilesDiffViewerRef {
  scrollToFile: (path: string) => void;
}

interface AllFilesDiffViewerProps {
  workspaceId: string;
  fileChanges: FileChange[];
  /** Hide the header bar (file count, collapse/expand). Used when
   *  the viewer is embedded inside ChangesView which has its own chrome. */
  hideHeader?: boolean;
  onActiveFileChange?: (filePath: string | null) => void;
  /** File to scroll to on mount (one-shot) */
  initialScrollTarget?: string;
}

export const AllFilesDiffViewer = forwardRef<AllFilesDiffViewerRef, AllFilesDiffViewerProps>(
  function AllFilesDiffViewer(
    { workspaceId, fileChanges, hideHeader, onActiveFileChange, initialScrollTarget },
    ref
  ) {
    const sectionRefsMap = useRef(new Map<string, HTMLDivElement>());
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const [activeFile, setActiveFile] = useState<string | null>(null);
    // Key counter for collapse-all/expand-all — incrementing remounts all sections expanded
    const [expandStateKey, setExpandStateKey] = useState(0);

    // Ref-based stable wrappers for props that change identity on refetch.
    const workspaceIdRef = useRef(workspaceId);
    const fileChangesRef = useRef(fileChanges);
    const onActiveFileChangeRef = useRef(onActiveFileChange);

    useEffect(() => {
      workspaceIdRef.current = workspaceId;
      fileChangesRef.current = fileChanges;
      onActiveFileChangeRef.current = onActiveFileChange;
    });

    // Clear ref maps on unmount to prevent stale entries
    useEffect(() => {
      return () => {
        sectionRefsMap.current.clear();
      };
    }, []);

    // Resolve a file path to its DOM element — ref map first, DOM query fallback.
    // content-visibility: auto can confuse ref-based lookups for off-screen elements,
    // so the data-diff-path selector provides a reliable backup.
    const resolveSection = useCallback((path: string): HTMLElement | null => {
      const el = sectionRefsMap.current.get(path);
      if (el) return el;
      // Fallback: query the scroll container by data attribute
      return (
        scrollContainerRef.current?.querySelector(`[data-diff-path="${CSS.escape(path)}"]`) ?? null
      );
    }, []);

    // --- Scroll-spy: centralized scroll event listener ---
    // Finds the topmost section whose top edge is at or above the container's
    // vertical midpoint. More reliable than distributed IntersectionObservers
    // in memoized children with content-visibility: auto.
    const activeFileRef = useRef<{ workspaceId: string; path: string | null }>({
      workspaceId,
      path: null,
    });

    // Shared helper — updates all active-file state + store in one place.
    const setActiveFilePath = useCallback((path: string | null) => {
      const currentWorkspaceId = workspaceIdRef.current;
      const prev = activeFileRef.current;
      if (prev.workspaceId === currentWorkspaceId && prev.path === path) return;
      activeFileRef.current = { workspaceId: currentWorkspaceId, path };
      setActiveFile(path);
      onActiveFileChangeRef.current?.(path);
      workspaceLayoutActions.setSelectedFilePath(currentWorkspaceId, path);
    }, []);

    useEffect(() => {
      const container = scrollContainerRef.current;
      if (!container) return;

      let rafId = 0;

      const updateActiveFile = () => {
        rafId = 0;
        const changes = fileChangesRef.current;
        if (changes.length === 0) return;

        const containerRect = container.getBoundingClientRect();
        // Threshold: a section is "active" if its top is within the top third
        // of the scroll container. This feels natural — the file you're reading
        // is the one near the top, not the one partially entering at the bottom.
        const threshold = containerRect.top + containerRect.height * 0.33;

        let best: string | null = null;

        for (const fc of changes) {
          const path = fc.file || fc.file_path || "";
          const el = sectionRefsMap.current.get(path);
          if (!el) continue;

          const rect = el.getBoundingClientRect();
          // Section is visible if its bottom is below container top AND its top
          // is above the threshold line.
          if (rect.bottom > containerRect.top && rect.top <= threshold) {
            best = path;
          }
        }

        // Fallback: if nothing passes the threshold (scrolled to very bottom),
        // pick the last section that's at least partially visible.
        if (best === null) {
          for (let i = changes.length - 1; i >= 0; i--) {
            const path = changes[i].file || changes[i].file_path || "";
            const el = sectionRefsMap.current.get(path);
            if (!el) continue;
            const rect = el.getBoundingClientRect();
            if (rect.top < containerRect.bottom && rect.bottom > containerRect.top) {
              best = path;
              break;
            }
          }
        }

        setActiveFilePath(best);
      };

      const onScroll = () => {
        if (rafId === 0) {
          rafId = requestAnimationFrame(updateActiveFile);
        }
      };

      container.addEventListener("scroll", onScroll, { passive: true });

      // Fire once on mount to set the initial active file
      requestAnimationFrame(updateActiveFile);

      return () => {
        container.removeEventListener("scroll", onScroll);
        if (rafId !== 0) cancelAnimationFrame(rafId);
      };
    }, []); // Stable — reads fileChanges via ref; section registration uses callback refs

    // One-shot scroll to initial target after sections mount and register refs
    useEffect(() => {
      if (!initialScrollTarget) return;
      const raf = requestAnimationFrame(() => {
        const target = resolveSection(initialScrollTarget);
        if (!target) return;
        setActiveFilePath(initialScrollTarget);
        target.scrollIntoView({
          behavior: "auto",
          block: "start",
        });
      });
      return () => cancelAnimationFrame(raf);
    }, [initialScrollTarget, workspaceId, resolveSection, setActiveFilePath]);

    // Expose scrollToFile to parent — immediately updates active file
    // so the tree highlight changes without waiting for the scroll event.
    useImperativeHandle(
      ref,
      () => ({
        scrollToFile(path: string) {
          setActiveFilePath(path);
          const el = resolveSection(path);
          if (el) {
            el.scrollIntoView({ behavior: "smooth", block: "start" });
          }
        },
      }),
      [workspaceId, resolveSection]
    );

    // Section ref callback — populates the ref map
    const sectionRefCallback = useCallback((filePath: string, el: HTMLDivElement | null) => {
      if (el) {
        sectionRefsMap.current.set(filePath, el);
      } else {
        sectionRefsMap.current.delete(filePath);
      }
    }, []);

    const handleCollapseExpandAll = useCallback(() => {
      setExpandStateKey((prev) => prev + 1);
    }, []);

    return (
      <div className="flex h-full flex-col overflow-hidden">
        {/* Header bar — hidden when embedded in ChangesView */}
        {!hideHeader && (
          <div className="bg-muted/20 border-border/40 flex h-8 flex-shrink-0 items-center justify-between border-b px-3">
            <span className="text-muted-foreground/70 text-xs tabular-nums">
              {fileChanges.length} {fileChanges.length === 1 ? "file" : "files"} changed
            </span>
            <button
              type="button"
              onClick={handleCollapseExpandAll}
              className="text-muted-foreground hover:text-foreground hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-200"
              title="Reset expand/collapse"
            >
              <ChevronsUpDown className="h-3.5 w-3.5" />
            </button>
          </div>
        )}

        {/* Scrollable file sections */}
        <div
          ref={scrollContainerRef}
          className="scrollbar-vibrancy flex flex-1 flex-col gap-3 overflow-y-auto pb-3"
        >
          {fileChanges.map((fc) => {
            const path = fc.file || fc.file_path || "";
            return (
              <AllDiffFileSection
                key={path}
                workspaceId={workspaceId}
                fileChange={fc}
                isActive={activeFile === path}
                sectionRef={sectionRefCallback}
                expandStateKey={expandStateKey}
              />
            );
          })}
        </div>
      </div>
    );
  }
);

import { useState, useMemo, useEffect, useCallback, type CSSProperties } from "react";
import { Copy, Check, Plus, X, MessageSquarePlus, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { FileDiff } from "@pierre/diffs/react";
import type { DiffLineAnnotation } from "@pierre/diffs/react";
import { getSingularPatch, parseDiffFromFile } from "@pierre/diffs";
import type { FileContents, FileDiffMetadata } from "@pierre/diffs";
import { useDiffOptions } from "@/shared/lib/diffOptions";
import { chatInsertActions } from "@/shared/stores/chatInsertStore";

interface DiffViewerProps {
  filePath?: string;
  diff?: string;
  oldContent?: string | null;
  newContent?: string | null;
  isLoading?: boolean;
  error?: string | null;
  onClose?: () => void;
  /** When true, renders with natural height (no h-full / internal scroll) for stacking inside a scrollable parent */
  embedded?: boolean;
  /** Required for sending diff comments to the chat input */
  workspaceId?: string;
}

/**
 * DiffViewer - Git diff viewer powered by @pierre/diffs
 *
 * Renders unified diffs with syntax highlighting, word-level change detection,
 * and hunk separators. Uses Shadow DOM for style isolation.
 *
 * Data flow: Backend returns raw diff + file contents → FileDiff parses and renders
 */
type CommentSide = "additions" | "deletions";

interface DiffComment {
  id: string;
  lineNumber: number;
  side: CommentSide;
  text: string;
  createdAt: string;
}

interface DiffCommentDraft {
  lineNumber: number;
  side: CommentSide;
  text: string;
}

interface DiffCommentMeta {
  id: string;
  text: string;
  createdAt?: string;
  isDraft?: boolean;
}

export function DiffViewer({
  filePath = "",
  diff = "",
  oldContent = null,
  newContent = null,
  isLoading = false,
  error: errorProp = null,
  onClose,
  embedded = false,
  workspaceId,
}: DiffViewerProps) {
  const [copied, setCopied] = useState(false);
  const [comments, setComments] = useState<DiffComment[]>([]);
  const [draftComment, setDraftComment] = useState<DiffCommentDraft | null>(null);
  const [showAll, setShowAll] = useState(false);

  const baseDiffOptions = useDiffOptions<DiffCommentMeta>();

  const handleCopyDiff = async () => {
    try {
      await navigator.clipboard.writeText(diff);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (error) {
      console.error("Failed to copy diff:", error);
    }
  };

  const diffIsEmpty = diff.trim().length === 0;
  const hasContent = !isLoading && !errorProp && !diffIsEmpty;

  const displayFileDiff = useMemo(() => {
    if (!diff.trim()) return null;
    const fallbackName = filePath || "file";
    const diffPaths = extractDiffPaths(diff);
    const oldName = diffPaths.oldPath || fallbackName;
    const newName = diffPaths.newPath || fallbackName;

    // Embedded mode (all-diffs view): lightweight patch-only parsing.
    // Skips parseDiffFromFile which processes full file contents synchronously.
    if (!embedded) {
      const oldFile: FileContents | null =
        oldContent != null ? { name: oldName, contents: oldContent } : null;
      const newFile: FileContents | null =
        newContent != null ? { name: newName, contents: newContent } : null;
      if (oldFile && newFile) {
        try {
          const generated = parseDiffFromFile(oldFile, newFile);
          return applyDisplayNames(generated, fallbackName);
        } catch (error) {
          console.warn("Failed to generate full diff, falling back to patch diff", error);
        }
      }
    }

    try {
      return applyDisplayNames(getSingularPatch(diff), fallbackName);
    } catch (error) {
      console.warn("Failed to parse patch diff", error);
      return null;
    }
  }, [diff, embedded, filePath, newContent, oldContent]);

  const canExpand = Boolean(displayFileDiff);

  useEffect(() => {
    // Reset comment state when file changes - intentional pattern for clearing related state
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setComments([]);
    setDraftComment(null);
    setShowAll(false);
  }, [filePath]);

  // Disable word-level diffs for large diffs (2000 line threshold)
  const isLargeDiff = useMemo(
    () => displayFileDiff != null && countDiffLines(displayFileDiff) > LARGE_DIFF_LINE_THRESHOLD,
    [displayFileDiff]
  );

  const diffOptions = useMemo(
    () => ({
      ...baseDiffOptions,
      overflow: "scroll" as const,
      disableFileHeader: true,
      enableHoverUtility: hasContent,
      expandUnchanged: showAll && canExpand,
      ...(isLargeDiff && { lineDiffType: "none" as const }),
    }),
    [baseDiffOptions, canExpand, embedded, hasContent, isLargeDiff, showAll]
  );

  const createCommentId = () =>
    `comment-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

  const handleStartComment = useCallback(
    (getHoveredLine: () => { lineNumber: number; side: CommentSide } | undefined) => {
      const hovered = getHoveredLine();
      if (!hovered) return;

      setDraftComment((current) => {
        if (current && current.lineNumber === hovered.lineNumber && current.side === hovered.side) {
          return current;
        }
        return { lineNumber: hovered.lineNumber, side: hovered.side, text: "" };
      });
    },
    []
  );

  const handleSaveDraft = useCallback(() => {
    const draft = draftComment;
    if (!draft) return;
    const trimmed = draft.text.trim();
    if (!trimmed) {
      setDraftComment(null);
      return;
    }
    const newComment: DiffComment = {
      id: createCommentId(),
      lineNumber: draft.lineNumber,
      side: draft.side,
      text: trimmed,
      createdAt: new Date().toISOString(),
    };
    setComments((prev) => [...prev, newComment]);
    setDraftComment(null);
  }, [draftComment]);

  const handleCancelDraft = useCallback(() => {
    setDraftComment(null);
  }, []);

  const handleRemoveComment = useCallback((id: string) => {
    setComments((prev) => prev.filter((comment) => comment.id !== id));
  }, []);

  const formatCommentForChat = useCallback(
    (comment: DiffComment, lineNumber: number, side: CommentSide) => {
      const fileLabel = filePath || "file";
      const sideLabel = side === "additions" ? "addition" : "deletion";
      return [
        "### 💬 Diff comment",
        `- **File:** \`${fileLabel}\``,
        `- **Line:** ${lineNumber} (${sideLabel})`,
        "",
        comment.text,
      ].join("\n");
    },
    [filePath]
  );

  const handleSendToChat = useCallback(
    (comment: DiffComment) => {
      if (!workspaceId) return;
      const text = formatCommentForChat(comment, comment.lineNumber, comment.side);
      chatInsertActions.insertText(workspaceId, text);
    },
    [formatCommentForChat, workspaceId]
  );

  const lineAnnotations = useMemo<DiffLineAnnotation<DiffCommentMeta>[]>(
    () => [
      ...comments.map((comment) => ({
        side: comment.side,
        lineNumber: comment.lineNumber,
        metadata: {
          id: comment.id,
          text: comment.text,
          createdAt: comment.createdAt,
        },
      })),
      ...(draftComment
        ? [
            {
              side: draftComment.side,
              lineNumber: draftComment.lineNumber,
              metadata: {
                id: "draft",
                text: draftComment.text,
                isDraft: true,
              },
            },
          ]
        : []),
    ],
    [comments, draftComment]
  );

  const renderAnnotation = useCallback(
    (annotation: DiffLineAnnotation<DiffCommentMeta>) => {
      const meta = annotation.metadata;
      if (!meta) return null;

      if (meta.isDraft) {
        const draft = draftComment;
        return (
          <div className="diff-comment-card">
            <Textarea
              value={draft?.text ?? ""}
              onChange={(event) =>
                setDraftComment((current) =>
                  current ? { ...current, text: event.target.value } : current
                )
              }
              placeholder="Add a review comment…"
              className="min-h-[88px] text-sm"
            />
            <div className="diff-comment-actions">
              <Button
                size="sm"
                className="diff-comment-save"
                onClick={handleSaveDraft}
                disabled={!draft?.text.trim()}
              >
                Save comment
              </Button>
              <Button size="sm" variant="ghost" onClick={handleCancelDraft}>
                Cancel
              </Button>
            </div>
          </div>
        );
      }

      const savedComment: DiffComment = {
        id: meta.id,
        lineNumber: annotation.lineNumber,
        side: annotation.side,
        text: meta.text,
        createdAt: meta.createdAt ?? "",
      };

      return (
        <div className="diff-comment-card">
          <p className="diff-comment-text">{meta.text}</p>
          <div className="diff-comment-actions">
            <Button size="sm" variant="ghost" onClick={() => handleSendToChat(savedComment)}>
              <MessageSquarePlus className="h-3.5 w-3.5" />
              Add to chat
            </Button>
            <Button size="sm" variant="ghost" onClick={() => handleRemoveComment(meta.id)}>
              Remove
            </Button>
          </div>
        </div>
      );
    },
    [draftComment, handleCancelDraft, handleRemoveComment, handleSaveDraft, handleSendToChat]
  );

  const headerActions = (
    <div className="diff-header-actions">
      <button
        type="button"
        className="diff-header-btn"
        onClick={() => setShowAll((prev) => !prev)}
        disabled={!canExpand}
        aria-pressed={showAll}
        title={canExpand ? undefined : "Full file context unavailable"}
      >
        {showAll ? "Collapse" : "Show all"}
      </button>
      <button
        type="button"
        className="diff-header-icon"
        onClick={handleCopyDiff}
        title={copied ? "Copied" : "Copy diff"}
      >
        {copied ? <Check className="h-3.5 w-3.5" /> : <Copy className="h-3.5 w-3.5" />}
      </button>
      {onClose && (
        <button type="button" className="diff-header-icon" onClick={onClose} title="Close diff">
          <X className="h-3.5 w-3.5" />
        </button>
      )}
    </div>
  );

  const headerTitle = useMemo(() => {
    if (!displayFileDiff) return null;
    if (displayFileDiff.prevName) {
      return (
        <span className="diff-viewer-title">
          <span className="diff-viewer-title-muted">{displayFileDiff.prevName}</span>
          <ArrowRight className="h-3.5 w-3.5 opacity-60" />
          <span>{displayFileDiff.name}</span>
        </span>
      );
    }
    return <span className="diff-viewer-title">{displayFileDiff.name}</span>;
  }, [displayFileDiff]);

  const diffContainerStyle = useMemo<CSSProperties>(
    () => ({
      height: embedded ? "auto" : "100%",
      overflow: embedded ? "visible" : "auto",
      // CSS variables pierce Shadow DOM — inline is the reliable delivery path
      "--diffs-font-size": "11px",
      "--diffs-line-height": "16px",
    }),
    [embedded]
  );

  return (
    <div className={embedded ? "" : "bg-background flex h-full flex-col overflow-hidden"}>
      {hasContent && displayFileDiff && !embedded && (
        <div className="diff-viewer-header">
          <div className="min-w-0 flex-1">{headerTitle}</div>
          {headerActions}
        </div>
      )}

      {/* Diff content */}
      <div className={embedded ? "relative" : "relative min-h-0 flex-1 overflow-hidden"}>
        {isLoading ? (
          <div className="flex h-full items-center justify-center px-6 py-10">
            <div className="w-full max-w-none animate-pulse space-y-3">
              <div className="bg-muted/40 h-4 w-32 rounded-full" />
              {["w-4/5", "w-3/4", "w-5/6", "w-2/3", "w-4/6", "w-3/5"].map((width, index) => (
                <div key={index} className="flex items-center gap-3">
                  <div className="bg-muted/30 h-3 w-10 rounded-md" />
                  <div className={`h-3 ${width} bg-muted/30 rounded-md`} />
                </div>
              ))}
            </div>
          </div>
        ) : errorProp ? (
          <div className="text-muted-foreground/60 flex h-64 items-center justify-center">
            <div className="flex max-w-sm flex-col items-center gap-2 text-center">
              <p className="text-sm">{errorProp}</p>
            </div>
          </div>
        ) : diffIsEmpty ? (
          <div className="text-muted-foreground/60 flex h-64 items-center justify-center">
            <p className="text-sm">No changes</p>
          </div>
        ) : !displayFileDiff ? (
          <div className="text-muted-foreground/60 flex h-64 items-center justify-center">
            <p className="text-sm">Unable to render diff</p>
          </div>
        ) : (
          <FileDiff<DiffCommentMeta>
            fileDiff={displayFileDiff}
            options={diffOptions}
            lineAnnotations={lineAnnotations}
            renderAnnotation={renderAnnotation}
            renderHoverUtility={(getHoveredLine) => (
              <button
                type="button"
                onClick={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  handleStartComment(getHoveredLine);
                }}
                className="diff-hover-action"
                title="Add comment"
              >
                <Plus className="h-3.5 w-3.5" />
              </button>
            )}
            className="diffs-theme diffs-theme-compact"
            style={diffContainerStyle}
          />
        )}
      </div>
    </div>
  );
}

// Above this threshold, disable word-level diffs
const LARGE_DIFF_LINE_THRESHOLD = 2000;

function countDiffLines(fileDiff: FileDiffMetadata): number {
  let total = 0;
  for (const hunk of fileDiff.hunks) {
    total += hunk.additionCount + hunk.deletionCount;
  }
  return total;
}

function applyDisplayNames(fileDiff: FileDiffMetadata, fallbackName: string): FileDiffMetadata {
  const displayName = toBaseName(fileDiff.name || fallbackName);
  const displayPrev = fileDiff.prevName ? toBaseName(fileDiff.prevName) : undefined;
  return {
    ...fileDiff,
    name: displayName,
    prevName: displayPrev,
  };
}

function toBaseName(path: string): string {
  const cleaned = normalizeGitPath(path);
  const parts = cleaned.split("/");
  return parts[parts.length - 1] || cleaned;
}

function extractDiffPaths(diff: string): { oldPath?: string; newPath?: string } {
  let oldPath: string | undefined;
  let newPath: string | undefined;
  const lines = diff.split("\n");
  for (const line of lines) {
    if (line.startsWith("rename from ")) {
      oldPath = normalizeGitPath(line.slice("rename from ".length));
      continue;
    }
    if (line.startsWith("rename to ")) {
      newPath = normalizeGitPath(line.slice("rename to ".length));
      continue;
    }
    if (line.startsWith("diff --git ")) {
      const tokens = splitGitDiffTokens(line.slice("diff --git ".length));
      if (!oldPath && tokens[0]) oldPath = normalizeGitPath(tokens[0]);
      if (!newPath && tokens[1]) newPath = normalizeGitPath(tokens[1]);
      continue;
    }
    if (line.startsWith("--- ") || line.startsWith("+++ ")) {
      const match = line.match(/^(---|\+\+\+)\s+([^\t\r\n]+)(.*)$/);
      if (!match) continue;
      const [, prefix, fileName] = match;
      if (fileName === "/dev/null") {
        continue;
      }
      if (prefix === "---" && !oldPath) {
        oldPath = normalizeGitPath(fileName);
      } else if (prefix === "+++" && !newPath) {
        newPath = normalizeGitPath(fileName);
      }
    }
    if (oldPath && newPath) {
      break;
    }
  }
  return { oldPath, newPath };
}

function splitGitDiffTokens(value: string): string[] {
  const tokens: string[] = [];
  let i = 0;
  while (i < value.length && tokens.length < 2) {
    while (value[i] === " ") i += 1;
    if (i >= value.length) break;
    if (value[i] === '"') {
      let end = i + 1;
      while (end < value.length && value[end] !== '"') end += 1;
      tokens.push(value.slice(i, Math.min(end + 1, value.length)));
      i = end + 1;
    } else {
      let end = i;
      while (end < value.length && value[end] !== " ") end += 1;
      tokens.push(value.slice(i, end));
      i = end + 1;
    }
  }
  return tokens;
}

function normalizeGitPath(pathToken: string): string {
  if (!pathToken) return pathToken;
  const unquoted =
    pathToken.startsWith('"') && pathToken.endsWith('"') ? pathToken.slice(1, -1) : pathToken;
  return unquoted.replace(/^a\//, "").replace(/^b\//, "");
}

/**
 * Tool Group Block — Stable Wrapper with Delayed Grouping
 *
 * Wraps consecutive tool_use blocks in a stable container that exists from the
 * first tool's render. During streaming the wrapper is invisible (no header,
 * tools fully visible). When the streak is "sealed" (text follows or turn
 * completes) and contains 2+ tools, a header appears and tools collapse.
 *
 * Collapse behavior:
 * Tools fully unmount when collapsed (AnimatePresence + conditional render).
 * This is intentional — zero DOM weight when collapsed, consistent with
 * ThinkingBlock and SubagentGroupBlock. Per-tool expand state resets on
 * reopen, which is acceptable since tool groups are bounded (2-15 items).
 */

import { useState, useMemo, memo } from "react";
import { ChevronRight, Layers } from "lucide-react";
import { AnimatePresence, m } from "framer-motion";
import { cn } from "@/shared/lib/utils";
import type { ToolUseBlock as ToolUseBlockType } from "@/shared/types";

import { ToolUseBlock } from "./ToolUseBlock";
import { useSession } from "../../context";

interface ToolGroupBlockProps {
  blocks: ToolUseBlockType[];
  isSealed: boolean;
}

const expandTransition = { duration: 0.2, ease: [0.165, 0.84, 0.44, 1] as const };

/**
 * Memoized: blocks is a stable array ref from groupToolStreaks (only changes
 * when actual tool blocks change), isSealed transitions false→true once.
 * Without memo, every new message in the turn re-renders all sibling groups.
 */
export const ToolGroupBlock = memo(function ToolGroupBlock({
  blocks,
  isSealed,
}: ToolGroupBlockProps) {
  const { toolResultMap } = useSession();

  // Show header only for sealed streaks with 2+ tools.
  // During streaming (unsealed), tools render individually — no header.
  // When sealed (text follows or turn completes), header appears and tools collapse.
  const showHeader = isSealed && blocks.length >= 2;

  // Expand state: manual override (null = use default).
  // Default: collapsed when header shows, expanded when no header.
  // When user toggles, manualExpanded locks their preference.
  const [manualExpanded, setManualExpanded] = useState<boolean | null>(null);
  const isExpanded = manualExpanded !== null ? manualExpanded : !showHeader;

  // For single tools or unsealed streaks: always open (wrapper invisible)
  const isOpen = showHeader ? isExpanded : true;

  // Unique tool names for collapsed summary: "Read, Grep, Edit"
  const toolSummary = useMemo(() => {
    const names = new Set(blocks.map((b) => b.name));
    return [...names].join(", ");
  }, [blocks]);

  return (
    <div className="flex flex-col" style={{ contain: "layout style" }}>
      {/* Header — only shown for sealed streaks with 2+ tools.
          CSS animation replaces Framer Motion m.div: plays once on mount then
          the element is a plain div with zero ongoing React overhead. */}
      {showHeader && (
        <div className="tool-group-header-enter">
          <button
            type="button"
            onClick={() => {
              setManualExpanded(!isExpanded);
            }}
            className={cn(
              "group flex items-center gap-2 px-2 py-1.5 text-sm",
              "w-full cursor-pointer text-left",
              "transition-opacity duration-150 ease-out",
              "opacity-80 hover:opacity-100",
              "focus-visible:ring-ring focus-visible:ring-2 focus-visible:outline-none"
            )}
            aria-expanded={isExpanded}
            aria-label={`${isExpanded ? "Collapse" : "Expand"} ${blocks.length} tool calls`}
          >
            <div className="flex min-w-0 flex-1 items-center gap-2">
              {/* Icon container — 14x14px, icon/chevron swap on hover */}
              <div className="relative h-3.5 w-3.5 flex-shrink-0">
                {/* Layers icon — hides on hover or expanded */}
                <div
                  className={cn(
                    "absolute top-0 left-0 transition-opacity duration-150 ease-out",
                    isExpanded ? "opacity-0" : "opacity-100 group-hover:opacity-0"
                  )}
                >
                  <Layers className="text-muted-foreground/70 h-3.5 w-3.5" />
                </div>

                {/* Chevron — shows on hover or expanded */}
                <ChevronRight
                  className={cn(
                    "text-muted-foreground/50 absolute top-0 left-0 h-3.5 w-3.5 transition-[transform,opacity] duration-150 ease-out",
                    isExpanded && "rotate-90",
                    isExpanded ? "opacity-100" : "opacity-0 group-hover:opacity-100"
                  )}
                  aria-hidden="true"
                />
              </div>

              {/* Tool count */}
              <span className="text-foreground/70 font-medium tabular-nums">
                {blocks.length} tool call{blocks.length !== 1 ? "s" : ""}
              </span>

              {/* Tool names summary (collapsed only) */}
              {!isExpanded && (
                <>
                  <span className="text-muted-foreground/30" aria-hidden="true">
                    ·
                  </span>
                  <span className="text-muted-foreground truncate">{toolSummary}</span>
                </>
              )}
            </div>
          </button>
        </div>
      )}

      {/* Content — AnimatePresence for enter/exit opacity fade.
          When collapsed, tool blocks unmount entirely — no DOM weight.
          When expanded, they mount with a subtle opacity fade. */}
      <AnimatePresence>
        {isOpen && (
          <m.div
            initial={showHeader ? { opacity: 0, height: 0 } : false}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            transition={expandTransition}
            className="flex flex-col gap-0.5 overflow-hidden"
          >
            {blocks.map((block) => (
              <ToolUseBlock key={block.id} block={block} toolResult={toolResultMap.get(block.id)} />
            ))}
          </m.div>
        )}
      </AnimatePresence>
    </div>
  );
});

/**
 * Base Tool Renderer (Pure & Minimal)
 *
 * Shared component for all tool renderers with consistent UI patterns:
 * - Expand/collapse with smooth transitions
 * - Error-only status (assume success by default)
 * - Clean, transparent design (no backgrounds or borders)
 * - Supports both new (children) and old (render props) APIs
 *
 * Benefits:
 * - Change header design once → affects all 15 tools
 * - Minimal, content-first aesthetic
 * - Backward compatible with existing tool renderers
 */

import { useState, type ReactNode } from "react";
import { ChevronRight, X } from "lucide-react";
import { AnimatePresence, motion } from "framer-motion";
import { cn } from "@/shared/lib/utils";
import type { ToolUseBlock, ToolResultBlock } from "@/shared/types";
import { ToolError } from "./ToolError";

export interface BaseToolRendererProps {
  // Identity
  toolName: string;
  icon: ReactNode;

  // Data
  toolUse: ToolUseBlock;
  toolResult?: ToolResultBlock;

  // Behavior
  defaultExpanded?: boolean;
  isLoading?: boolean; // True when tool result is pending (shimmer effect)
  showContentOnError?: boolean; // True for tools whose renderContent already displays error output (e.g. Bash)

  // Content rendering (choose one)
  children?: ReactNode; // NEW API: Single children slot
  renderContent?: (props: {
    toolUse: ToolUseBlock;
    toolResult?: ToolResultBlock;
    isExpanded: boolean;
  }) => ReactNode; // OLD API
  renderSummary?: (props: { toolUse: ToolUseBlock }) => ReactNode; // Preview when collapsed
}

const expandTransition = { duration: 0.15, ease: [0.165, 0.84, 0.44, 1] as const };

export function BaseToolRenderer({
  toolName,
  icon,
  toolUse,
  toolResult,
  defaultExpanded = false, // Collapsed by default (explicit is better than implicit)
  isLoading = false,
  showContentOnError = false,
  children,
  renderContent,
  renderSummary,
}: BaseToolRendererProps) {
  const isError = toolResult?.is_error;

  // Errors never auto-expand — agents self-correct and errors are transient.
  // The X icon swap on the collapsed row is the error signal; users expand when they want details.
  const [manualExpanded, setManualExpanded] = useState<boolean | null>(null);
  const isExpanded = manualExpanded !== null ? manualExpanded : defaultExpanded;

  return (
    <div className="flex flex-col gap-1">
      {/* Header - Minimal, no borders or backgrounds.
          Uses CSS group hover for icon swap (no re-renders on mouse enter/leave). */}
      <button
        type="button"
        onClick={() => {
          setManualExpanded(!isExpanded);
        }}
        className={cn(
          "group flex items-center gap-2 px-2 py-1.5 text-sm",
          "w-full cursor-pointer text-left",
          "transition-opacity duration-150 ease-out",
          "opacity-80 hover:opacity-100",
          "focus-visible:ring-ring focus-visible:ring-2 focus-visible:outline-none"
        )}
        aria-expanded={isExpanded}
        aria-label={`${isExpanded ? "Collapse" : "Expand"} ${toolName} tool details`}
      >
        <div className="flex min-w-0 flex-1 items-center gap-2">
          {/* Icon container - fixed width to prevent layout shift.
              On error: X icon replaces tool icon (instant scan signal). */}
          <div className="relative h-3.5 w-3.5 flex-shrink-0">
            {/* Tool icon or error X — default state (hides on hover or when expanded) */}
            <div
              className={cn(
                "absolute top-0 left-0 transition-opacity duration-150 ease-out",
                isExpanded ? "opacity-0" : "opacity-100 group-hover:opacity-0"
              )}
            >
              {isError ? (
                <X className="text-destructive/70 h-3.5 w-3.5" aria-hidden="true" />
              ) : (
                icon
              )}
            </div>

            {/* Chevron - shows on hover or when expanded */}
            <ChevronRight
              className={cn(
                "text-muted-foreground/50 absolute top-0 left-0 h-3.5 w-3.5 transition-[transform,opacity] duration-150 ease-out",
                isExpanded && "rotate-90",
                isExpanded ? "opacity-100" : "opacity-0 group-hover:opacity-100"
              )}
              aria-hidden="true"
            />
          </div>

          {/* Tool name — shimmer when loading. */}
          <span
            className={cn(
              "flex-shrink-0 font-medium",
              isLoading ? "text-muted-foreground tool-loading-shimmer" : "text-foreground/70"
            )}
          >
            {toolName}
          </span>

          {/* Preview when collapsed */}
          {!isExpanded && renderSummary && (
            <span className="text-muted-foreground truncate">{renderSummary({ toolUse })}</span>
          )}
        </div>
      </button>

      {/* Expanded content — AnimatePresence for smooth height + opacity transition. */}
      <AnimatePresence initial={false}>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={expandTransition}
            style={{ overflow: "hidden" }}
            className="mt-0.5 ml-6"
          >
            {isError && toolResult && !showContentOnError ? (
              <ToolError content={toolResult.content} />
            ) : (
              <>
                {children}
                {!children && renderContent && renderContent({ toolUse, toolResult, isExpanded })}
              </>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

